\section{Absolute cohomological purity for flat cohomology}

\subsection{Purity theorems}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.1 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: For a perfectoid $\bZ_p$-algebra $A$, a commutative, finite, locally free $A$-group $G$ of $p$-power order, and a closed subset $Z \subset \Spec (A/pA)$ such that $\depth_Z(A) \ge d$ in the sense that there is an $A$-regular sequence $a_1, \dotsc, a_d \in A$ that vanishes on $Z$
\begin{definition}[Depth with support]
  \label{def:depth_Z}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.depthZ}
  \uses{}
  \textit{Source: Cesnavicius--Scholze, §1.1.}
  For a ring \(A\) and a closed subset \(Z \subset \operatorname{Spec}(A)\), write \(\operatorname{depth}_Z(A) \ge d\) if there exists an \(A\)-regular sequence \(a_1, \ldots, a_d \in A\) vanishing on \(Z\).
\end{definition}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.1 Purity theorems (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[Theorems~\ref{main-pf} and \ref{thm:main-pf-regular}] \label{main}
% For a Noetherian local ring $(R, \fm)$ that is a complete intersection\footnote{Recall that $(R, \fm)$ is a \emph{complete intersection} if its %$\fm$-adic
% completion is a quotient of a regular %local
% ring by a regular sequence.} and a commutative, finite, flat $R$-group scheme $G$,
% \[
% H^i_\fm(R, G) \cong 0 \q \text{for} \q \begin{cases} i < \dim(R); \\ i \le \dim(R), \qx{if $R$ is regular and not a field.} \end{cases}
% \]
% \ethm
\begin{theorem}[Purity for flat cohomology]
  \label{thm:main}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.purityForFlatCohomology}
  \uses{def:ci_local_ring, def:finite_flat_group, def:flat_cohomology_support}
  \textit{Source: Cesnavicius--Scholze, Theorems~1.1 and 1.2.}
  For a Noetherian local ring \((R, \mathfrak{m})\) that is a complete intersection and a commutative finite flat \(R\)-group scheme \(G\),
  \[
    H^i_{\mathfrak{m}}(R, G) = 0 \quad \text{for } \begin{cases} i < \dim(R); \\ i \le \dim(R), \quad \text{if } R \text{ is regular and not a field.} \end{cases}
  \]
\end{theorem}

% SOURCE QUOTE PROOF: In summary, the overall proof of the purity for flat cohomology of \Cref{main} proceeds as follows.
% \benuma
% \m
% Use a Lefschetz hyperplane theorem in local \'{e}tale cohomology to deduce the prime to the residue characteristic aspects from the purity for \'{e}tale cohomology of \Cref{abs-coh-pur-ann}
% (see~\S\ref{et-depth-geom-depth}).
%
% \m
% Use crystalline Dieudonn\'{e} theory to establish the positive characteristic case of the key formula \eqref{eqn:key-formula} %in the case when $A$ is a (perfect) $\bF_p$-algebra
% (see \S\ref{section:Dieudonne-positive-characteristic}); this already mostly settles \Cref{main} when $R$ is an $\bF_p$-algebra.% positive characteristic case.
%
% \m \label{step-3}
% Use the positive characteristic case of the key formula \eqref{eqn:key-formula} and animated deformation theory to show the new properties of fppf cohomology stated in Theorems \ref{thm:excision-ann}--\ref{thm:descent-ann} (see \S\S\ref{sec:defthy}--\ref{sec:descent}).
%
% \m
% Combine $p$-complete arc descent of \Cref{thm:descent-ann} with prismatic Dieudonn\'{e} theory to establish the key formula \eqref{eqn:key-formula} in general; deduce the perfectoid purity \Cref{thm:perfectoid-purity-ann} (see \S\ref{perfectoid-version}).
%
% \m \label{step-5}
% Combine excision obtained in \Cref{thm:excision-ann}, a version of Andr\'{e}'s lemma (see \S\ref{And-lem}), and deformation theory to reduce \Cref{main} to the perfectoid purity \Cref{thm:perfectoid-purity-ann} (see \S\ref{grand-finale}).
% \eenum
\begin{proof}
  \uses{thm:abs_coh_pur, thm:perfectoid_purity, thm:excision}
  By \cref{thm:excision}, one reduces to the case where \(R\) is complete. The prime-to-residue-characteristic case (order of \(G\) invertible in \(R/\mathfrak{m}\)) is deduced from the étale purity of \cref{thm:abs_coh_pur} via a Lefschetz hyperplane theorem in local étale cohomology.

  For the \(p\)-primary part with \(p = \operatorname{char}(R/\mathfrak{m}) > 0\): André's lemma produces a flat ind-syntomic perfectoid cover of the completion. The complete intersection hypothesis ensures that the intervening square-zero ideals (arising from killing the regular sequence \(f_1, \ldots, f_c\) that cuts out \(\widehat{R}\) in a regular ring) are free modules and thus of sufficient depth for deformation theory. Excision (\cref{thm:excision}) and the perfectoid purity (\cref{thm:perfectoid_purity}) then give the vanishing.
\end{proof}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.1 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[\Cref{abs-coh-pur}] \label{abs-coh-pur-ann}
% For a regular local ring $(R, \fm)$ and a commutative, finite, \'{e}tale $R$-group $G$ whose order is invertible in $R$,
% \[
% H^i_\fm(R, G) \cong 0 \qxq{for} i < 2\dim(R).
% \]
% \ethm
\begin{theorem}[Étale cohomological purity]
  \label{thm:abs_coh_pur}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.absCohomlPurity}
  \uses{def:flat_cohomology_support}
  \textit{Source: Cesnavicius--Scholze, §1.1 (Theorem on absolute cohomological purity).}
  For a regular local ring \((R, \mathfrak{m})\) and a commutative finite étale \(R\)-group scheme \(G\) whose order is invertible in \(R\),
  \[
    H^i_{\mathfrak{m}}(R, G) = 0 \quad \text{for } i < 2\dim(R).
  \]
\end{theorem}

\begin{proof}
  \uses{}
  This is proved by Gabber (first in the framework of Thomason's \(K\)-theoretic approach, then in \cite{ILO14}). The paper gives a new proof reducing to positive characteristic via perfectoid techniques.
\end{proof}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.1 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[\Cref{ell-semipurity-p}] \label{ell-semipurity-ann}
% For a Noetherian local ring $(R, \fm)$ and a commutative, finite, \'{e}tale $R$-group $G$,
% \[
% H^i_\fm(R, G) \cong 0 \qxq{for} i < \vdim(R).
% \]
% \ethm
\begin{theorem}[Étale semipurity]
  \label{thm:ell_semipurity}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.etaleSemipurity}
  \uses{def:flat_cohomology_support, def:virtual_dim}
  \textit{Source: Cesnavicius--Scholze, §1.1.}
  For a Noetherian local ring \((R, \mathfrak{m})\) and a commutative finite étale \(R\)-group scheme \(G\),
  \[
    H^i_{\mathfrak{m}}(R, G) = 0 \quad \text{for } i < \vdim(R).
  \]
\end{theorem}

\begin{proof}
  \uses{thm:abs_coh_pur}
  Deduced from \cref{thm:abs_coh_pur} using a Lefschetz hyperplane theorem in local étale cohomology and induction on the number of generators of the defining ideal of \(\widehat{R}\).
\end{proof}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.1 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[\Cref{thm:perfectoid-purity}] \label{thm:perfectoid-purity-ann}
% For a perfectoid $\bZ_p$-algebra $A$, a commutative, finite, locally free $A$-group $G$ of $p$-power order, and a closed subset $Z \subset \Spec (A/pA)$ such that $\depth_Z(A) \ge d$ in the sense that there is an $A$-regular sequence $a_1, \dotsc, a_d \in A$ that vanishes on $Z$, we have
% \[
% H^i_Z(A, G) \cong 0 \qxq{for} i < d.
% \]
% \ethm
\begin{theorem}[Perfectoid purity]
  \label{thm:perfectoid_purity}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.perfectoidPurity}
  \uses{def:perfectoid_ring, def:flat_cohomology_support, def:depth_Z}
  \textit{Source: Cesnavicius--Scholze, §1.1.}
  For a perfectoid \(\mathbb{Z}_p\)-algebra \(A\), a commutative finite locally free \(A\)-group scheme \(G\) of \(p\)-power order, and a closed subset \(Z \subset \operatorname{Spec}(A/pA)\) with \(\operatorname{depth}_Z(A) \ge d\),
  \[
    H^i_Z(A, G) = 0 \quad \text{for } i < d.
  \]
\end{theorem}

% SOURCE QUOTE PROOF: For instance, a basic case is when $A$ is a perfect $\bF_p$-algebra. Then, by results of Berthelot \cite{Ber80}, Gabber (unpublished), and Lau \cite{Lau13}, such $A$-groups $G$ are classified by their crystalline Dieudonn\'{e} modules $\bM(G)$, which are $p$-power torsion, finitely presented $W(A)$-modules (that is, $\bA_\Inf(A)$-modules) of projective dimension $\le 1$ equipped with semilinear Frobenius and Verschiebung endomorphisms $F$ and $V$. We use this classification to describe the flat cohomology with coefficients in $G$ in terms of the quasi-coherent cohomology with coefficients in $\bM(G)$: we show in \Cref{KT-input} that
% \be\tag{$1.1.6$} \label{eqn:key-formula}
% R\Gamma_Z(A, G) \cong R\Gamma_Z(\bA_\Inf(A), \bM(G))^{V - 1}.
% \ee
% Since $p$ is a nonzerodivisor in $\bA_\Inf(A)$, the sequence $p, a_1, \dotsc, a_d$ is regular in $\bA_\Inf(A)$ and vanishes on $Z$. By expressing $\bM(G)$ as the cokernel of a map between finite projective $\bA_\Inf(A)$-modules, we may then deduce the vanishing of the right side of \eqref{eqn:key-formula} in the desired range of degrees from the fact that ``enough depth'' implies the vanishing of quasi-coherent cohomology with supports.
\begin{proof}
  \uses{thm:arc_descent}
  The flat cohomology \(R\Gamma_Z(A, G)\) is computed via the key formula
  \[
    R\Gamma_Z(A, G) \cong R\Gamma_Z(\mathbb{A}_{\mathrm{Inf}}(A), \mathbb{M}(G))^{V-1},
  \]
  where \(\mathbb{M}(G)\) is the prismatic Dieudonné module of \(G\). Since \(p\) is a nonzerodivisor in \(\mathbb{A}_{\mathrm{Inf}}(A)\), the sequence \(\xi, a_1, \ldots, a_d\) (where \(\xi\) generates \(\ker(\theta)\)) is regular in \(\mathbb{A}_{\mathrm{Inf}}(A)\) and vanishes on \(Z\). Expressing \(\mathbb{M}(G)\) as the cokernel of a map between finite projective \(\mathbb{A}_{\mathrm{Inf}}(A)\)-modules, the vanishing of quasi-coherent cohomology with supports in the required range gives the result. The key formula is proved using \cref{thm:arc_descent}.
\end{proof}

