\end{proof}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.2 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[\Cref{adic-continuity}] \label{adic-continuity-ann}
% For a ring $R$, an animated $R$-algebra $A$, elements $a_1, \dotsc, a_r \in A$ such that $A$ agrees with its iterated derived $a_i$-adic completion for $i = 1, \dotsc, r$, and a commutative, finite, locally free $R$-group $G$,
% \[
% \tst R\Gamma(A, G) \isomto R\lim_{n > 0} (R\Gamma(A/^\bL (a_1^n, \dotsc, a_r^n), G)).
% \]
% \ethm
\begin{theorem}[Iterated adic continuity]
  \label{thm:adic_continuity}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.adicContinuity}
  \uses{def:flat_cohomology_support}
  \textit{Source: Cesnavicius--Scholze, §1.2.}
  For a ring \(R\), an animated \(R\)-algebra \(A\), elements \(a_1, \ldots, a_r \in A\) such that \(A\) agrees with its iterated derived \(a_i\)-adic completion for \(i = 1, \ldots, r\), and a commutative finite locally free \(R\)-group scheme \(G\),
  \[
    R\Gamma(A, G) \xrightarrow{\sim} R\lim_{n > 0} \left( R\Gamma(A/^{\mathbf{L}} (a_1^n, \ldots, a_r^n), G) \right).
  \]
  The \(p\)-adic continuity of \cref{thm:p_adic_continuity} is the special case \(r = 1\), \(a_1 = p\).
\end{theorem}

\begin{proof}
  \uses{thm:p_adic_continuity}
  Deduced from the positive characteristic case of the key formula \eqref{eqn:key-formula} via crystalline Dieudonné theory: after identifying \(R\Gamma((-)[1/p], G)\) with étale cohomology and applying arc descent, one works along \(\{p = 0\}\) to reduce to \(p\)-Henselian and then \(\mathbb{F}_p\)-algebras using the general \(p\)-adic continuity result of \cref{thm:p_adic_continuity}.
\end{proof}

% SOURCE: [Cesnavicius--Scholze, arXiv:1912.10932], §1.2 (read from references/MR4681144-flat-cohomology-source/flat-purity.tex)
% SOURCE QUOTE: \bthm[\Cref{thm:padiclimit}] \label{thm:p-adic-continuity-ann}
% For a prime $p$, a ring $R$, a commutative, finite, locally free $R$-group $G$ of $p$-power order, and an animated $R$-algebra $A$ for which the ring $\pi_0(A)$ is $p$-Henselian,
% \[
% \tst R\Gamma_\fppf(A, G) \isomto R\lim_{n > 0}\p{R\Gamma_\fppf(A/^\bL p^n, G)}\!.
% \]
% \ethm
\begin{theorem}[\(p\)-adic continuity]
  \label{thm:p_adic_continuity}
  \lean{MR4681144PurityForFlatCohomology.Basic.TODO.padicContinuity}
  \uses{def:flat_cohomology_support}
  \textit{Source: Cesnavicius--Scholze, §1.2.}
  For a prime \(p\), a ring \(R\), a commutative finite locally free \(R\)-group scheme \(G\) of \(p\)-power order, and an animated \(R\)-algebra \(A\) for which \(\pi_0(A)\) is \(p\)-Henselian,
  \[
    R\Gamma_{\mathrm{fppf}}(A, G) \xrightarrow{\sim} R\lim_{n > 0} R\Gamma_{\mathrm{fppf}}(A/^{\mathbf{L}} p^n, G).
  \]
\end{theorem}

